solutions.python:
from express import Flask, jsonify, Blueprint
app = Flask(__name__)

# Custom router for the '/api/users/:id' route
users_router = Blueprint('users', __name__)
@users_router.route('/<int:id>', methods=['GET'])
def get_user(id):
  # Handle the GET request to '/api/users/:id'
  user = { 'name': 'John Doe', 'email': 'john@example.com' }
  return jsonify(user)

# Main router
main_router = Blueprint('main', __name__)
main_router.register_blueprint(users_router, url_prefix='/api/users')
app.register_blueprint(main_router)

# Route middleware that handles the '/api/users' route
@app.route('/api/users', methods=['GET'])
def get_users():
  # Handle the GET request to '/api/users'
  return jsonify({ 'message': 'Hello, World!' })

# Start the server
if __name__ == '__main__':
  app.run(debug=True)
